// generar_267_momentos_de_vida.js
// CHIQUI Entre Señales — Momentos de vida (cualquier edad) + cambios
// propios de la edad
//
// IMPORTANTE: primero corre sql_267_momentos.sql en Supabase
// (New snippet) — crea la tabla momentos con RLS.
//
// 1) 💛 MOMENTOS DE SU VIDA — sección nueva en el registro diario,
//    visible a CUALQUIER edad (no depende de la etapa). 10 opciones:
//
//    🏡 El día que llegó a casa · 🏠 Se mudó de casa ·
//    👶 Llegó un nuevo integrante · 🐾 Conoció a un nuevo compañero
//    peludo · ✂️ Esterilización · ✈️ Su primer viaje ·
//    🌊 Conoció el mar · 💪 Superó una enfermedad ·
//    🕊️ Se despidió de un compañero · 💛 Otro momento (texto libre)
//
//    Al tocar uno se abre un modal con un campo de recuerdo opcional
//    y se guarda con la fecha del registro. A diferencia de los hitos
//    de cachorro, un momento PUEDE REPETIRSE (una segunda mudanza,
//    otro integrante): la tabla no tiene UNIQUE por tipo y cada
//    registro es un evento con su propia fecha.
//
//    Debajo del catálogo aparece la línea de tiempo de lo ya
//    registrado; tocando cualquiera se ve su detalle con la fecha y
//    la opción de corregir con confirmación (igual que los hitos).
//
//    Valor clínico: los cambios de entorno explican muchos cambios de
//    conducta, apetito o sueño. Tener la fecha ayuda a interpretar
//    después lo que el tutor observa.
//
// 2) 👀 CAMBIOS PROPIOS DE LA EDAD — tarjeta que aparece desde los 7
//    años (umbral "Adulto Maduro" de calcularEtapaVida, la edad en
//    que suele comenzar la esclerosis nuclear).
//
//    NO se presenta como un logro ni se celebra: es informativa y
//    deriva al veterinario. Explica que el interior del ojo se vea
//    más azulado suele ser un cambio normal del cristalino que no
//    afecta mayormente la visión, PERO que se parece mucho a las
//    cataratas, que sí necesitan revisión — y que solo el veterinario
//    puede distinguirlas. Al registrarlo queda la fecha con el
//    recordatorio "🩺 Coméntalo en el próximo control veterinario".
//
//    Se decidió NO incluir otros "cambios de senior" (le cuesta
//    saltar, camina más lento, escucha menos, bebe más agua) porque
//    NO son cambios benignos: son signos que merecen consulta y deben
//    pasar por Observaciones o Signos de alerta, donde ya existe el
//    semáforo y la derivación al veterinario. Registrarlos como
//    "hitos" tiernos podría retrasar un diagnóstico tratable.
//
// 3) CALENDARIO — los momentos aparecen en el día que ocurrieron:
//    marca 💛 en la esquina de la celda (distinta de la 🐾 de los
//    hitos) y tarjeta al abrir el día. Los cambios de la edad se
//    muestran con tono neutro, sin dorado ni celebración.
//
// Uso:
//   1) SQL primero: sql_267_momentos.sql → Run
//   2) node generar_267_momentos_de_vida.js
//   3) git add . && commit && push

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "app/registro-diario/page.tsx",
    base64: ""
  },
  {
    ruta: "app/calendario/page.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 2 archivos escritos.')
  console.log('Recuerda: SQL primero, luego git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
